import{_ as a,o as r,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"68. Cultural And Ceremonial Leave","description":"","frontmatter":{"title":"68. Cultural And Ceremonial Leave","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","ceremonial-leave"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/leave/68-cultural-and-ceremonial-leave.md","filePath":"ebas/has-managers-admin/common-terms/leave/68-cultural-and-ceremonial-leave.md"}'),t={name:"ebas/has-managers-admin/common-terms/leave/68-cultural-and-ceremonial-leave.md"};function l(i,e,s,m,c,d){return r(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_68-cultural-and-ceremonial-leave" tabindex="-1">68. Cultural And Ceremonial Leave <a class="header-anchor" href="#_68-cultural-and-ceremonial-leave" aria-label="Permalink to &quot;68. Cultural And Ceremonial Leave&quot;">​</a></h1><p><strong>68.1</strong> The Employer may approve attendance during working hours by an Employee of Aboriginal or Torres Strait Islander descent at any Aboriginal community meetings, except the Annual general Meetings of Aboriginal community organisations at which the election of office bearers will occur.</p><p><strong>68.2</strong> The Employer may grant an Employee of Aboriginal or Torres Strait Islander descent accrued annual or other leave to attend the Annual General Meetings of Aboriginal community organisations at which the election of office bearers will occur.</p><p><strong>68.3</strong> Ceremonial leave without pay may be granted to an Employee of Aboriginal or Torres Strait Islander descent for ceremonial purposes:</p><p><strong>(a)</strong> connected with the death of a member of the immediate family or extended family (provided that no Employee will have an existing entitlement reduced as a result of this clause); or</p><p><strong>(b)</strong> for other ceremonial obligations under Aboriginal or Torres Strait Islander law.</p><p><strong>68.4</strong> Ceremonial leave granted under this clause is in addition to compassionate leave granted under any other provision of the Agreement.</p><p>Plain language terms: cultural leave, sorry business, aboriginal ceremony, religious ceremony.</p>',8)])])}const p=a(t,[["render",l]]);export{g as __pageData,p as default};
